function Itinerary({ itinerary }) {

  if (!itinerary) return null;

  return (

    <div className="card">

      <h2>Trip Itinerary</h2>

      {
        itinerary.map((day, index) => (

          <div
            key={index}
            className="item"
          >

            <p>{day}</p>

          </div>
        ))
      }

    </div>
  );
}

export default Itinerary;
